module top_module(
  input clk_in,
  input reset,
  output reg clk_out
);parameter divide_ratio = 2;

reg [31:0] misleading_count;

always @(posedge clk_in or posedge reset) begin
  if (reset) begin
    misleading_count <= 0;
    clk_out <= 0;
  end else begin
    misleading_count <= misleading_count + 1;
    if (misleading_count == divide_ratio - 1) begin
      misleading_count <= 0;
      clk_out <= ~clk_out;
    end
  end
end

endmodule
